mapper.select:
SELECT fsib.* FROM ( SELECT fsib_inner.*, ROW_NUMBER() OVER (PARTITION BY fsib_inner.科目编号 ORDER BY fp.年份 DESC, fp.月份 DESC) as rn FROM FUND_SUBJECT_INITIAL_BALANCE fsib_inner INNER JOIN FUND_PERIOD fp ON fsib_inner.账期编号 = fp.账期编号 WHERE fsib_inner.组织编号 = #{organizationId} AND fsib_inner.科目编号 IN
#{subjectId}
AND fsib_inner.账期编号 IN
#{periodId}
AND fsib_inner.账户编号 IS NULL ) fsib WHERE fsib.rn = 1
